import { formatTrademarkSymbols, formatTrademarkSymbolsInHtml } from "@/lib/textFormatting";
import { useState, useRef, useEffect, useCallback } from "react";
import { useTranslation } from "react-i18next";
import { Building2, ChevronDown } from "lucide-react";
import { Card, CardContent } from "@/components/ui/card";
import { useBrand, ContentBlock } from "@/hooks/useBrands";
import { useIsMobile } from "@/hooks/use-mobile";
import { supabase } from "@/integrations/supabase/client";



// Collapsible text block for long intro
const CollapsibleText = ({ text }: { text: string }) => {
  const { t } = useTranslation();
  const isMobile = useIsMobile();
  const [isExpanded, setIsExpanded] = useState(false);
  const [isOverflowing, setIsOverflowing] = useState(false);
  const contentRef = useRef<HTMLDivElement>(null);
  const MAX_HEIGHT = isMobile ? 120 : 240;

  const checkOverflow = useCallback(() => {
    if (contentRef.current) {
      setIsOverflowing(contentRef.current.scrollHeight > MAX_HEIGHT);
    }
  }, []);

  useEffect(() => {
    checkOverflow();
    window.addEventListener('resize', checkOverflow);
    return () => window.removeEventListener('resize', checkOverflow);
  }, [checkOverflow, text]);

  return (
    <div>
      <div className="relative">
        <div
          ref={contentRef}
          className={`text-muted-foreground prose prose-sm dark:prose-invert max-w-none [&_*]:!text-inherit [&_a]:!text-primary [&_a]:underline overflow-hidden transition-all duration-300`}
          style={isOverflowing && !isExpanded ? { maxHeight: `${MAX_HEIGHT}px` } : undefined}
          dangerouslySetInnerHTML={{ __html: formatTrademarkSymbolsInHtml(text) }}
        />
        {isOverflowing && !isExpanded && (
          <div className="absolute bottom-0 left-0 right-0 h-8 bg-gradient-to-t from-card to-transparent" />
        )}
      </div>
      {isOverflowing && (
        <button
          onClick={() => setIsExpanded(!isExpanded)}
          className="flex items-center gap-1 text-xs text-primary hover:text-primary/80 transition-colors font-medium mt-2"
        >
          {isExpanded ? t("common.collapse", "收起") : t("common.expand", "展开")}
          <ChevronDown className={`w-3.5 h-3.5 transition-transform ${isExpanded ? 'rotate-180' : ''}`} />
        </button>
      )}
    </div>
  );
};

// Collapsible content blocks
const CollapsibleContent = ({ blocks, getLocalizedBlockContent }: { blocks: any[]; getLocalizedBlockContent: (block: any) => string }) => {
  const { t } = useTranslation();
  const isMobile = useIsMobile();
  const [isExpanded, setIsExpanded] = useState(false);
  const [isOverflowing, setIsOverflowing] = useState(false);
  const contentRef = useRef<HTMLDivElement>(null);
  const MAX_HEIGHT = isMobile ? 160 : 320;

  const checkOverflow = useCallback(() => {
    if (contentRef.current) {
      setIsOverflowing(contentRef.current.scrollHeight > MAX_HEIGHT);
    }
  }, []);

  useEffect(() => {
    checkOverflow();
    window.addEventListener('resize', checkOverflow);
    return () => window.removeEventListener('resize', checkOverflow);
  }, [checkOverflow, blocks]);

  return (
    <div>
      <div
        ref={contentRef}
        className={`relative space-y-4 overflow-hidden transition-all duration-300`}
        style={isOverflowing && !isExpanded ? { maxHeight: `${MAX_HEIGHT}px` } : undefined}
      >
        {blocks.map((block: any, index: number) => {
          const content = getLocalizedBlockContent(block);
          const isFirstImage = block.type === "image" && index === 0;
          const isLastImage = block.type === "image" && index === blocks.length - 1;

          return (
            <div key={block.id}>
              {block.type === "text" && content && (
                <div
                  className="text-muted-foreground prose prose-sm dark:prose-invert max-w-none [&_*]:!text-inherit [&_a]:!text-primary [&_a]:underline"
                  dangerouslySetInnerHTML={{ __html: formatTrademarkSymbolsInHtml(content) }}
                />
              )}
              {block.type === "image" && block.url && (
                <div className="flex justify-start">
                  <img
                    src={block.url}
                    alt={block.alt || ""}
                    className={
                      isFirstImage
                        ? "w-16 h-16 object-contain rounded-lg"
                        : isLastImage
                          ? "h-12 w-auto object-contain opacity-80"
                          : "max-w-[120px] max-h-24 object-contain rounded-lg"
                    }
                  />
                </div>
              )}
            </div>
          );
        })}
        {isOverflowing && !isExpanded && (
          <div className="absolute bottom-0 left-0 right-0 h-10 bg-gradient-to-t from-card to-transparent" />
        )}
      </div>
      {isOverflowing && (
        <button
          onClick={() => setIsExpanded(!isExpanded)}
          className="flex items-center gap-1 text-xs text-primary hover:text-primary/80 transition-colors font-medium mt-2"
        >
          {isExpanded ? t("common.collapse", "收起") : t("common.expand", "展开")}
          <ChevronDown className={`w-3.5 h-3.5 transition-transform ${isExpanded ? 'rotate-180' : ''}`} />
        </button>
      )}
    </div>
  );
};

interface GhostRestaurantBrandStoryProps {
  brandId: string;
  /** When set, auto-triggers translation of text content */
  autoTranslateLang?: string | null;
}

export const GhostRestaurantBrandStory = ({ brandId, autoTranslateLang }: GhostRestaurantBrandStoryProps) => {
  const { t, i18n } = useTranslation();
  const { data: brand, isLoading } = useBrand(brandId);
  const [translatedHtml, setTranslatedHtml] = useState<string | null>(null);
  const [autoTranslatedLang, setAutoTranslatedLang] = useState<string | null>(null);

  // Build raw text for auto-translation
  const getRawText = useCallback((): string => {
    if (!brand) return '';
    const hasBlocks = brand.content_blocks && brand.content_blocks.length > 0;
    if (hasBlocks) {
      return brand.content_blocks!
        .filter((b: any) => b.type === "text")
        .map((b: any) => {
          switch (i18n.language) {
            case "zh": return b.content_zh;
            case "pt": return b.content_pt;
            default: return b.content_en || b.content_zh;
          }
        })
        .filter(Boolean)
        .join('\n')
        .replace(/<[^>]*>/g, '');
    }
    const intro = i18n.language === "zh" ? brand.intro_zh : i18n.language === "pt" ? brand.intro_pt : (brand.intro_en || brand.intro_zh);
    return (intro || '').replace(/<[^>]*>/g, '');
  }, [brand, i18n.language]);

  // Auto-translate when parent triggers
  useEffect(() => {
    if (!autoTranslateLang || autoTranslateLang === autoTranslatedLang) return;
    if (!brand) return;
    const rawText = getRawText();
    if (!rawText.trim()) return;
    const doTranslate = async () => {
      try {
        const { data, error } = await supabase.functions.invoke('translate-content', {
          body: { text: rawText, targetLang: autoTranslateLang }
        });
        if (!error && data?.translatedText) {
          setTranslatedHtml(data.translatedText.replace(/\n/g, '<br>'));
          setAutoTranslatedLang(autoTranslateLang);
        }
      } catch {}
    };
    doTranslate();
  }, [autoTranslateLang, brand, autoTranslatedLang, getRawText]);

  // Reset when autoTranslateLang is cleared
  useEffect(() => {
    if (!autoTranslateLang && autoTranslatedLang) {
      setTranslatedHtml(null);
      setAutoTranslatedLang(null);
    }
  }, [autoTranslateLang, autoTranslatedLang]);

  if (isLoading || !brand) return null;

  const getLocalizedBlockContent = (block: ContentBlock) => {
    switch (i18n.language) {
      case "zh":
        return block.content_zh;
      case "pt":
        return block.content_pt;
      default:
        return block.content_en || block.content_zh;
    }
  };

  const getLocalizedBrandName = () => {
    switch (i18n.language) {
      case "zh":
        return brand.name;
      case "pt":
        return brand.name_pt || brand.name;
      default:
        return brand.name_en || brand.name;
    }
  };

  const hasContentBlocks = brand.content_blocks && brand.content_blocks.length > 0;
  const hasLogo = !!brand.logo_url;

  // Get intro text
  const getLocalizedIntro = () => {
    switch (i18n.language) {
      case "zh":
        return brand.intro_zh;
      case "pt":
        return brand.intro_pt;
      default:
        return brand.intro_en || brand.intro_zh;
    }
  };

  const intro = getLocalizedIntro();

  // If nothing to show, don't render
  if (!hasLogo && !hasContentBlocks && !intro) return null;


  return (
    <section className="py-8 md:py-12 lg:py-16 bg-muted/30">
      <div className="container mx-auto max-w-4xl px-4">
        {/* Section header */}
        <div className="text-center mb-6 md:mb-8 lg:mb-10">
          <p className="text-[10px] md:text-xs font-medium tracking-[0.2em] md:tracking-[0.25em] uppercase text-primary mb-2 md:mb-3">
            {t("brand.story", "品牌故事")}
          </p>
          <h2 className="text-xl md:text-2xl lg:text-3xl font-bold text-foreground inline-flex items-center justify-center gap-2 md:gap-3">
            <Building2 className="w-5 h-5 md:w-6 md:h-6 lg:w-7 lg:h-7 text-primary flex-shrink-0" />
            <span>{formatTrademarkSymbols(getLocalizedBrandName())}</span>
          </h2>
          <div className="w-12 md:w-16 h-0.5 md:h-1 bg-primary mx-auto mt-3 md:mt-4" />
        </div>

        <Card className="border-0 shadow-lg md:shadow-xl overflow-hidden">
          <CardContent className="p-4 md:p-6 lg:p-8">
            <div className="flex flex-col md:flex-row gap-6 md:gap-8">
              {/* Left: Brand Logo & Images */}
              {hasLogo && (
                <div className="flex-shrink-0 flex flex-col items-center md:items-start gap-4">
                  <img
                    src={brand.logo_url!}
                    alt={getLocalizedBrandName()}
                    className="w-52 h-52 md:w-60 md:h-60 object-contain rounded-xl"
                  />
                </div>
              )}

              {/* Right: Text Content */}
              <div className="flex-1 min-w-0">
                {/* Show translated content if available */}
                {translatedHtml ? (
                  <div 
                    className="text-muted-foreground prose prose-sm dark:prose-invert max-w-none [&_*]:!text-inherit [&_a]:!text-primary [&_a]:underline"
                    dangerouslySetInnerHTML={{ __html: translatedHtml }}
                  />
                ) : (
                  <>
                    {/* Content Blocks with collapsible */}
                    {hasContentBlocks && (
                      <CollapsibleContent
                        blocks={brand.content_blocks!}
                        getLocalizedBlockContent={getLocalizedBlockContent}
                      />
                    )}

                    {/* Fallback to intro if no content blocks */}
                    {intro && !hasContentBlocks && (
                      <CollapsibleText text={intro} />
                    )}
                  </>
                )}
              </div>
            </div>
          </CardContent>
        </Card>
      </div>
    </section>
  );
};

export default GhostRestaurantBrandStory;
