import { memo, useState, useCallback } from "react";
import { useActiveStoreAds } from "@/hooks/useStoreAds";
import { useTranslation } from "react-i18next";
import { Link, useNavigate } from "react-router-dom";
import { Megaphone } from "lucide-react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import ExternalLinkConfirmDialog from "@/components/ExternalLinkConfirmDialog";
import { openExternalUrl } from "@/lib/externalLinks";

interface StoreAdBannerProps {
  country: string | null;
  city: string | null;
  storeLevel: string;
}

const useRentalBannerConfig = () => {
  return useQuery({
    queryKey: ["rental-banner-config"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("site_settings")
        .select("rental_banner_enabled, rental_banner_email, rental_banner_text_zh, rental_banner_text_en, rental_banner_text_pt, rental_banner_desc_zh, rental_banner_desc_en, rental_banner_desc_pt")
        .single();
      if (error) throw error;
      return data;
    },
    staleTime: 5 * 60 * 1000,
  });
};

const StoreAdBanner = memo(({ country, city, storeLevel }: StoreAdBannerProps) => {
  const { t, i18n } = useTranslation();
  const { data: ads } = useActiveStoreAds(country, city);
  const { data: rentalConfig } = useRentalBannerConfig();
  const lang = i18n.language;

  const [pendingUrl, setPendingUrl] = useState<string | null>(null);
  const [pendingAdName, setPendingAdName] = useState<string | null>(null);

  // Only show for unclaimed (shell) stores
  if (storeLevel !== 'shell') return null;

  const validAds = (ads || []).filter(ad => ad.image_url);
  const showRental = rentalConfig?.rental_banner_enabled !== false;

  // Nothing to show
  if (validAds.length === 0 && !showRental) return null;

  const rentalLabel = lang === "zh"
    ? (rentalConfig?.rental_banner_text_zh || "广告位招租")
    : lang === "pt"
      ? (rentalConfig?.rental_banner_text_pt || "Espaço Publicitário")
      : (rentalConfig?.rental_banner_text_en || "Ad Space Available");

  const rentalDesc = lang === "zh"
    ? (rentalConfig?.rental_banner_desc_zh || "首月免费 · 点击了解详情")
    : lang === "pt"
      ? (rentalConfig?.rental_banner_desc_pt || "Primeiro mês grátis · Clique para saber mais")
      : (rentalConfig?.rental_banner_desc_en || "First month free · Click for details");

  const navigate = useNavigate();

  const isInternalLink = (url: string) => url.startsWith("/");

  const handleAdClick = (url: string, name: string) => {
    if (isInternalLink(url)) {
      navigate(url);
    } else {
      setPendingUrl(url);
      setPendingAdName(name);
    }
  };

  const handleConfirm = () => {
    if (pendingUrl) {
      openExternalUrl(pendingUrl);
      setPendingUrl(null);
      setPendingAdName(null);
    }
  };

  return (
    <>
      <div className="space-y-3">
        {/* Actual ads */}
        {validAds.map((ad) => {
          const content = (
            <div key={ad.id} className="relative rounded-xl overflow-hidden border border-border/50 shadow-sm">
              <div className="absolute top-2 left-2 z-10">
                <span className="inline-flex items-center px-2 py-0.5 rounded-md text-[10px] font-medium bg-background/80 backdrop-blur-sm text-muted-foreground border border-border/50">
                  {t("common.ad")}
                </span>
              </div>
              <div className="w-full bg-muted h-28 sm:h-32 md:h-36 lg:h-40">
                <img src={ad.image_url!} alt={ad.name} className="w-full h-full object-cover" loading="lazy" />
              </div>
              {ad.description && (
                <div className="absolute bottom-0 inset-x-0 bg-gradient-to-t from-black/60 to-transparent p-3 pt-6">
                  <p className="text-white text-sm font-medium line-clamp-2">{ad.description}</p>
                </div>
              )}
              <div className="absolute bottom-2 right-2 z-10">
                <span className="inline-flex items-center px-2 py-0.5 rounded-md text-[10px] bg-background/70 backdrop-blur-sm text-muted-foreground">
                  {t("storeAd.unclaimedOnly")}
                </span>
              </div>
            </div>
          );

          if (ad.link_url) {
            return (
              <div
                key={ad.id}
                role="button"
                tabIndex={0}
                className="block cursor-pointer hover:opacity-95 transition-opacity"
                onClick={() => handleAdClick(ad.link_url!, ad.name)}
                onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') handleAdClick(ad.link_url!, ad.name); }}
              >
                {content}
              </div>
            );
          }
          return <div key={ad.id}>{content}</div>;
        })}

        {/* Ad space for rent - always at the bottom */}
        {showRental && (
          <Link to="/ad-space" className="block hover:opacity-90 transition-opacity">
            <div className="relative rounded-xl overflow-hidden border-2 border-dashed border-muted-foreground/30 bg-muted/20 hover:border-primary/40 hover:bg-primary/5 transition-colors">
              <div className="absolute top-2 left-2 z-10">
                <span className="inline-flex items-center px-2 py-0.5 rounded-md text-[10px] font-medium bg-background/80 backdrop-blur-sm text-muted-foreground border border-border/50">
                  {t("common.ad")}
                </span>
              </div>
              <div className="flex flex-col items-center justify-center py-8 px-4">
                <div className="rounded-full bg-primary/10 p-3 mb-3">
                  <Megaphone className="h-6 w-6 text-primary" />
                </div>
                <p className="font-semibold text-sm text-foreground">{rentalLabel}</p>
                <p className="text-xs text-muted-foreground mt-1">{rentalDesc}</p>
              </div>
              <div className="absolute bottom-2 right-2 z-10">
                <span className="inline-flex items-center px-2 py-0.5 rounded-md text-[10px] bg-background/70 backdrop-blur-sm text-muted-foreground">
                  {t("storeAd.unclaimedOnly")}
                </span>
              </div>
            </div>
          </Link>
        )}
      </div>

      {/* External Link Confirmation Dialog */}
      <ExternalLinkConfirmDialog
        open={!!pendingUrl}
        onOpenChange={(open) => { if (!open) { setPendingUrl(null); setPendingAdName(null); } }}
        onConfirm={handleConfirm}
        url={pendingUrl || undefined}
        title={t("common.adLinkTitle")}
        description={t("common.adLinkDescription", { name: pendingAdName || "" })}
        confirmLabel={t("common.adLinkContinue")}
      />
    </>
  );
});

StoreAdBanner.displayName = "StoreAdBanner";

export default StoreAdBanner;
